checks.run:
mkdir -p "$SANDBOX/test"
cat > "$SANDBOX/test/_grader.test.ts" <<'GRADER'
import { test } from "node:test";
import assert from "node:assert/strict";
import { createService } from "../src/index.ts";
import { IllegalTransitionError, NotFoundError } from "../src/errors.ts";

function published(s) {
  const d = s.createDraft("t", "b");
  s.submitForReview(d.id);
  s.publish(d.id);
  return d.id;
}

test("archive a published doc: status, timestamp, event", () => {
  const { service, bus } = createService();
  const events = [];
  bus.on((e) => events.push(e.type));
  const id = published(service);
  const d = service.archive(id);
  assert.equal(d.status, "archived");
  assert.ok(d.archivedAt && d.archivedAt > 0);
  assert.equal(events.at(-1), "archived");
});

test("archive a doc still in review", () => {
  const { service } = createService();
  const d = service.createDraft("t", "b");
  service.submitForReview(d.id);
  assert.equal(service.archive(d.id).status, "archived");
});

test("cannot archive a draft", () => {
  const { service } = createService();
  const d = service.createDraft("t", "b");
  assert.throws(() => service.archive(d.id), IllegalTransitionError);
});

test("archive unknown id throws NotFoundError", () => {
  const { service } = createService();
  assert.throws(() => service.archive("nope"), NotFoundError);
});

test("restore an archived doc back to draft, clearing archivedAt and emitting", () => {
  const { service, bus } = createService();
  const id = published(service);
  service.archive(id);
  const events = [];
  bus.on((e) => events.push(e.type));
  const d = service.restore(id);
  assert.equal(d.status, "draft");
  assert.equal(d.archivedAt, undefined);
  assert.equal(events.at(-1), "draft");
});

test("cannot restore a doc that is not archived", () => {
  const { service } = createService();
  const id = published(service);
  assert.throws(() => service.restore(id), IllegalTransitionError);
});

test("listByStatus surfaces archived docs", () => {
  const { service, repo } = createService();
  const id = published(service);
  service.archive(id);
  assert.deepEqual(repo.listByStatus("archived").map((d) => d.id), [id]);
});
GRADER
cd "$SANDBOX" && node --experimental-strip-types --test "test/existing.test.ts" "test/_grader.test.ts"
